class RecipeFilter{constructor({listSelector,itemSelector,categoryAttr="categories",ingredientAttr="ingredients",statusSelector=null,noResultsSelector=null,formSelector=null,resetButtonSelector=null,categoryInputName="category",ingredientInputName="ingredient",urlCategoryParam="category",urlIngredientParam="ingredient",statusText="{count} of {total} recipes are shown",statusFiltered="filtered"}){this.listEl=document.querySelector(listSelector);if(!this.listEl){throw new Error(`RecipeFilter: Container "${ listSelector }" not found.`)}this.itemSelector=itemSelector;this.categoryAttr=categoryAttr;this.ingredientAttr=ingredientAttr;this.statusEl=statusSelector?document.querySelector(statusSelector):null;this.noResultsEl=noResultsSelector?document.querySelector(noResultsSelector):null;this.activeCategories=new Set();this.activeIngredients=new Set();this.items=Array.from(this.listEl.querySelectorAll(this.itemSelector));this.formEl=formSelector?document.querySelector(formSelector):null;this.resetButtonEl=resetButtonSelector?document.querySelector(resetButtonSelector):null;this.categoryInputName=categoryInputName;this.ingredientInputName=ingredientInputName;this.urlCategoryParam=urlCategoryParam;this.urlIngredientParam=urlIngredientParam;this.statusText=statusText;this.statusFiltered=statusFiltered;if(this.formEl){this._onFormChange=this._handleFormChange.bind(this);this._onResetClick=this._handleResetClick.bind(this);this._onPopState=this._handlePopState.bind(this);this.formEl.addEventListener("change",this._onFormChange);if(this.resetButtonEl){this.resetButtonEl.addEventListener("click",this._onResetClick)}window.addEventListener("popstate",this._onPopState);this._applyUrlToCheckboxes();this.setFilters({categories:this._readCheckedValues(this.categoryInputName),ingredients:this._readCheckedValues(this.ingredientInputName)})}else{this.apply()}}destroy(){if(!this.formEl){return}this.formEl.removeEventListener("change",this._onFormChange);if(this.resetButtonEl){this.resetButtonEl.removeEventListener("click",this._onResetClick)}window.removeEventListener("popstate",this._onPopState)}_readCheckedValues(inputName){return Array.from(this.formEl.querySelectorAll(`input[name="${ inputName }"]:checked`)).map((input)=>input.value)}_setCheckedValues(inputName,values){const valueSet=new Set(values);this.formEl.querySelectorAll(`input[name="${ inputName }"]`).forEach((cb)=>{cb.checked=valueSet.has(cb.value)})}_syncUrlFromFilters(categories,ingredients){const params=new URLSearchParams(window.location.search);categories.length?params.set(this.urlCategoryParam,categories.join(",")):params.delete(this.urlCategoryParam);ingredients.length?params.set(this.urlIngredientParam,ingredients.join(",")):params.delete(this.urlIngredientParam);const queryString=params.toString();const newUrl=`${window.location.pathname }${queryString?"?"+queryString:""}${window.location.hash }`;history.replaceState(null,"",newUrl)}_readUrlParamValues(paramName){const params=new URLSearchParams(window.location.search);const raw=params.get(paramName);return raw?raw.split(",").map((v)=>v.trim()).filter(Boolean):[]}_applyUrlToCheckboxes(){this._setCheckedValues(this.categoryInputName,this._readUrlParamValues(this.urlCategoryParam));this._setCheckedValues(this.ingredientInputName,this._readUrlParamValues(this.urlIngredientParam))}_handleFormChange(){const categories=this._readCheckedValues(this.categoryInputName);const ingredients=this._readCheckedValues(this.ingredientInputName);this.setFilters({categories,ingredients});this._syncUrlFromFilters(categories,ingredients)}_handleResetClick(){this.formEl.querySelectorAll('input[type="checkbox"]').forEach((cb)=>(cb.checked=false));this.reset();this._syncUrlFromFilters([],[])}_handlePopState(){this._applyUrlToCheckboxes();this.setFilters({categories:this._readCheckedValues(this.categoryInputName),ingredients:this._readCheckedValues(this.ingredientInputName)})}_readAttrSet(el,attrName){const raw=el.dataset[attrName]||"";return new Set(raw.split(",").map((v)=>v.trim().toLowerCase()).filter(Boolean))}matches(el){const itemCategories=this._readAttrSet(el,this.categoryAttr);const itemIngredients=this._readAttrSet(el,this.ingredientAttr);const categoryOk=this.activeCategories.size===0||[...this.activeCategories].some((c)=>itemCategories.has(c));const ingredientOk=this.activeIngredients.size===0||[...this.activeIngredients].some((i)=>itemIngredients.has(i));return categoryOk&&ingredientOk}setFilters({categories=[],ingredients=[]}={}){this.activeCategories=new Set(categories.map((c)=>c.toLowerCase()));this.activeIngredients=new Set(ingredients.map((i)=>i.toLowerCase()));this.apply()}reset(){this.activeCategories.clear();this.activeIngredients.clear();this.apply()}apply(){let visibleCount=0;this.items.forEach((el)=>{const isMatch=this.matches(el);el.hidden=!isMatch;if(isMatch){visibleCount+=1}});if(this.noResultsEl){this.noResultsEl.hidden=visibleCount!==0}this._announce(visibleCount);return visibleCount}_announce(count){if(!this.statusEl){return}const total=this.items.length;this.statusEl.textContent=count===total?this.statusText.replaceAll('{count}',count.toString()).replaceAll('{total}',total.toString()):this.statusText.replaceAll('{count}',count.toString()).replaceAll('{total}',total.toString())+'('+this.statusFiltered+')'}}